targets.expr:
(
  sum by (container) (
    rate(container_cpu_usage_seconds_total{namespace="backend", pod=~".*", image!="", container=~"$container", cluster=~".*"}[$__rate_interval])
  )
/
  sum by (container) (
    kube_pod_container_resource_limits{namespace="backend", pod=~".*", resource="cpu", container=~"$container", cluster=~".*"}
  )
) * 100

(
  sum by (container) (
    container_memory_working_set_bytes{namespace="backend", pod=~".*", image!="", container=~"$container", cluster=~".*"}
  )
/
  sum by (container) (
    kube_pod_container_resource_limits{namespace="backend", pod=~".*", resource="memory", container=~"$container", cluster=~".*"}
  )
) * 100
